const items = $input.all();
const out = [];
for (const item of items) {
  const binaryKeys = Object.keys(item.binary || {});
  const pdfKeys = binaryKeys.filter((k) => {
    const b = item.binary[k];
    return (b.mimeType || '').toLowerCase().includes('pdf') || (b.fileName || '').toLowerCase().endsWith('.pdf');
  });
  if (pdfKeys.length === 0) {
    // No PDF attachment -> not an invoice email, drop silently but log
    continue;
  }
  for (const key of pdfKeys) {
    out.push({
      json: {
        sender: item.json.from?.text || item.json.from || '',
        senderEmail: (item.json.from?.value?.[0]?.address) || item.json.from || '',
        senderName: (item.json.from?.value?.[0]?.name) || '',
        subject: item.json.subject || '',
        receivedAt: item.json.date || new Date().toISOString(),
        attachmentKey: key,
        fileName: item.binary[key].fileName || 'invoice.pdf',
      },
      binary: { attachment_0: item.binary[key] },
    });
  }
}
return out;

// This PDF has no usable text layer (likely a scanned image).
// Per project constraints, NO OCR is used. Route to manual data entry.
const item = $input.first();
return [{
  json: {
    ...item.json,
    applicationStatus: 'Manual Data Entry Required',
    anomalies: ['PDF has no extractable text layer (likely scanned). OCR is disabled by design; manual data entry required.'],
  },
  binary: item.binary,
}];

const fs = require('fs');
const path = '/data/prompts/invoice_extraction_prompt.txt';
let template;
try {
  template = fs.readFileSync(path, 'utf8');
} catch (e) {
  // Fallback: template mounted elsewhere or embedded via n8n static data
  template = $getWorkflowStaticData('global').promptTemplate;
}
const invoiceText = $json.text || '';
const rendered = template.replace('{{invoiceText}}', invoiceText.slice(0, 100000));
return [{ json: { ...$json, renderedPrompt: rendered } }];

// Parse, clean, and validate Gemini's JSON output. Never trusts AI blindly.
function safeParseJson(raw) {
  if (!raw || !raw.trim()) throw new Error('Empty AI response');
  let candidate = raw.trim();
  const fence = candidate.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fence) candidate = fence[1].trim();
  const a = candidate.indexOf('{');
  const b = candidate.lastIndexOf('}');
  if (a !== -1 && b !== -1 && b > a) candidate = candidate.slice(a, b + 1);
  return JSON.parse(candidate);
}
function toNum(v) {
  if (v === null || v === undefined || v === '') return null;
  if (typeof v === 'number' && Number.isFinite(v)) return v;
  const n = parseFloat(String(v).replace(/[^0-9.\-]/g, ''));
  return Number.isFinite(n) ? n : null;
}
function toIsoDate(v) {
  if (!v || typeof v !== 'string') return null;
  return /^\d{4}-\d{2}-\d{2}$/.test(v.trim()) ? v.trim() : null;
}

const item = $input.first();
const candidatesText = item.json?.candidates?.[0]?.content?.parts?.map(p => p.text).join('') || '';
const parsed = safeParseJson(candidatesText);

const anomalies = Array.isArray(parsed.anomalies) ? [...parsed.anomalies] : [];
const netAmount = toNum(parsed.netAmount);
const vatAmount = toNum(parsed.vatAmount);
const grossAmount = toNum(parsed.grossAmount);
if (netAmount !== null && vatAmount !== null && grossAmount !== null) {
  const expected = Math.round((netAmount + vatAmount) * 100) / 100;
  const actual = Math.round(grossAmount * 100) / 100;
  if (Math.abs(expected - actual) > 0.02) anomalies.push(`Net+VAT (${expected}) != Gross (${actual})`);
}
const invoiceNumber = parsed.invoiceNumber ? String(parsed.invoiceNumber).trim() : null;
if (!invoiceNumber) anomalies.push('invoiceNumber missing.');
const vendor = parsed.vendor ? String(parsed.vendor).trim() : null;
if (!vendor) anomalies.push('vendor missing.');

const cleaned = {
  vendor,
  vendorUid: parsed.vendorUid || null,
  vendorIban: parsed.vendorIban ? String(parsed.vendorIban).replace(/\s+/g, '') : null,
  invoiceNumber,
  invoiceDate: toIsoDate(parsed.invoiceDate),
  dueDate: toIsoDate(parsed.dueDate),
  netAmount, vatAmount, grossAmount,
  vatPercent: toNum(parsed.vatPercent),
  currency: parsed.currency ? String(parsed.currency).toUpperCase().slice(0, 3) : null,
  costCenter: parsed.costCenter || null,
  lineItems: Array.isArray(parsed.lineItems) ? parsed.lineItems.filter(li => li && li.description).map(li => ({ description: String(li.description).slice(0, 500), quantity: toNum(li.quantity), unitPrice: toNum(li.unitPrice), lineTotal: toNum(li.lineTotal) })) : [],
  documentType: ['invoice','credit_note','receipt','unknown'].includes(parsed.documentType) ? parsed.documentType : 'unknown',
  language: parsed.language || 'unknown',
  confidence: Math.min(1, Math.max(0, toNum(parsed.confidence) || 0)),
  anomalies,
};

const validationErrors = [];
if (!cleaned.invoiceNumber) validationErrors.push('missing_invoice_number');
if (!cleaned.vendor) validationErrors.push('missing_vendor');

return [{
  json: { ...$('Filter PDF Attachments + Extract Metadata').first().json, extracted: cleaned, validationErrors },
  binary: $('Filter PDF Attachments + Extract Metadata').first().binary,
}];

function normalize(v) { return v ? String(v).trim().toUpperCase().replace(/[^A-Z0-9]/g, '') : ''; }
const extracted = $('Clean & Validate AI Output').first().json.extracted;
const existing = $input.all();
const amountKey = (extracted.grossAmount ?? 'NA');
const candidateKey = [normalize(extracted.vendor), normalize(extracted.invoiceNumber), normalize(extracted.invoiceDate), amountKey].join('|');
let isDuplicate = false;
let matches = [];
for (const rec of existing) {
  const f = rec.json;
  const existingKey = [normalize(f['Vendor']), normalize(f['Invoice Number']), normalize(f['Invoice Date']), f['Gross Amount'] ?? 'NA'].join('|');
  if (existingKey === candidateKey) { isDuplicate = true; matches.push(rec.json.id); }
}
const base = $('Clean & Validate AI Output').first().json;
return [{ json: { ...base, duplicateCheck: { isDuplicate, matches } } }];

function normalize(v) { return v ? String(v).trim().toUpperCase().replace(/[^A-Z0-9]/g, '') : ''; }
function similarity(a, b) {
  const s1 = normalize(a), s2 = normalize(b);
  if (!s1 || !s2) return 0;
  if (s1 === s2) return 1;
  const costs = [];
  for (let i = 0; i <= s1.length; i++) {
    let lastValue = i;
    for (let j = 0; j <= s2.length; j++) {
      if (i === 0) costs[j] = j;
      else if (j > 0) {
        let newValue = costs[j - 1];
        if (s1.charAt(i - 1) !== s2.charAt(j - 1)) newValue = Math.min(newValue, lastValue, costs[j]) + 1;
        costs[j - 1] = lastValue; lastValue = newValue;
      }
    }
    if (i > 0) costs[s2.length] = lastValue;
  }
  const distance = costs[s2.length];
  const maxLen = Math.max(s1.length, s2.length);
  return maxLen === 0 ? 1 : 1 - distance / maxLen;
}

const base = $('Evaluate Duplicate Matches').first().json;
const extracted = base.extracted;
const vendors = $input.all().map(v => v.json);
let status = 'unknown', matchedVendorId = null, confidence = 0;
const warnings = [];

if (extracted.vendorUid) {
  const uidMatch = vendors.find(v => normalize(v['Vendor UID']) === normalize(extracted.vendorUid));
  if (uidMatch) { status = 'known'; matchedVendorId = uidMatch.id; confidence = 0.98; }
}
if (status === 'unknown') {
  const nameMatch = vendors.find(v => normalize(v['Vendor Name']) === normalize(extracted.vendor));
  if (nameMatch) {
    status = 'known'; matchedVendorId = nameMatch.id; confidence = 0.95;
    if (extracted.vendorIban && nameMatch['IBAN'] && normalize(nameMatch['IBAN']) !== normalize(extracted.vendorIban)) {
      warnings.push('IBAN differs from vendor master - possible payment redirection fraud.');
    }
  }
}
if (status === 'unknown') {
  let best = null, bestScore = 0;
  for (const v of vendors) { const s = similarity(v['Vendor Name'], extracted.vendor); if (s > bestScore) { bestScore = s; best = v; } }
  if (best && bestScore >= 0.8) { status = 'possible_match'; matchedVendorId = best.id; confidence = bestScore; warnings.push(`Vendor name close to "${best['Vendor Name']}" (similarity ${bestScore.toFixed(2)})`); }
  else warnings.push(`Vendor "${extracted.vendor}" not found in master - requires onboarding/verification.`);
}

// Cost center prediction (keyword fallback; vendor history omitted here for brevity, extend as needed)
const KEYWORD_RULES = [
  { costCenter: 'IT-OPS', keywords: ['software','saas','subscription','cloud','hosting','license'] },
  { costCenter: 'MARKETING', keywords: ['advertising','campaign','marketing','branding','seo'] },
  { costCenter: 'FACILITIES', keywords: ['rent','lease','cleaning','utilities','maintenance'] },
  { costCenter: 'TRAVEL', keywords: ['flight','hotel','airfare','travel','taxi'] },
  { costCenter: 'LEGAL', keywords: ['legal','attorney','law firm','compliance'] },
  { costCenter: 'HR', keywords: ['recruiting','payroll','benefits','training'] },
  { costCenter: 'LOGISTICS', keywords: ['shipping','freight','courier','logistics'] },
];
let predictedCC = extracted.costCenter, ccSource = extracted.costCenter ? 'AI Extracted' : null;
if (!predictedCC) {
  const haystack = [extracted.vendor || '', ...(extracted.lineItems || []).map(li => li.description || '')].join(' ').toLowerCase();
  let bestMatch = null, bestScore = 0;
  for (const rule of KEYWORD_RULES) {
    const score = rule.keywords.reduce((acc, kw) => acc + (haystack.includes(kw) ? 1 : 0), 0);
    if (score > bestScore) { bestScore = score; bestMatch = rule.costCenter; }
  }
  if (bestMatch) { predictedCC = bestMatch; ccSource = 'Predicted'; }
}

return [{ json: { ...base, vendorValidation: { status, matchedVendorId, confidence, warnings }, predictedCostCenter: predictedCC, costCenterSource: ccSource } }];

const base = $('Vendor Validation + Cost Center Prediction').first().json;
const drive = $input.first().json;
const driveLink = drive.webViewLink || drive.webContentLink || '';
const isDuplicate = base.duplicateCheck?.isDuplicate;
const extracted = base.extracted;

const applicationStatus = isDuplicate ? 'Draft' : 'Draft'; // duplicates still created as Draft but flagged, human decides

return [{ json: { ...base, driveLink, applicationStatus } }];

