// Gemini call failed after retries -> build dead-letter payload
const item = $input.first();
const base = $('Filter PDF Attachments + Extract Metadata').first().json;
return [{
  json: {
    stage: 'AI_EXTRACTION',
    errorMessage: item.json?.error?.message || item.error?.message || 'Unknown Gemini error',
    payload: JSON.stringify(base).slice(0, 90000),
    timestamp: new Date().toISOString(),
  },
}];

